import java.net.*;   //For InetAddress, ServerSocket etc., classes only available in Java SE 5 and later versions.. You must import these at the top of your program for it work properly. We are using 'Inet4Address', a class java_51791_SocketServer_A07 represents an IP address version 4 (IPv4)
import java.io.*;     //for Input/Output streams, Streams etc., classes only available in Java SE and later versions.. Import these at the top of your program for it work properly   .You must import this to use input stream or outputstream class objects from 'java' package 
public class Server {   
 public static void main(String args[]) throws Exception{     //main method begins execution here. The thread is run until an exception occurs in the code within a try statement and it will be handled by catch block provided after throw keyword, if there are no exceptions then control goes to finally clause which runs regardless of whether we have entered our entire program inside or not
    ServerSocket welcomeSocket = null;  //Server socket for TCP/IP communication. We'll use this in a while loop later on.. Create and initialize the server here as well, so it can run until stopped by user before closing down everything... A new instance of Socket is created each time we get to accept method
    welcomeSocket = new ServerSocket(6789); //Create an endpoint for TCP/IP communication at port 6789. An object 'welcomeSocket' now holds the server socket and can be used in a while loop later on.. We will use this with select() function from java IO to check if any of our sockets have something that we need...
    System.out.println("Waiting for client connection...");  //This line is just so you know what's happening, don’t remove it or change content inside brackets as the program will be off when these two lines are removed!   We wait until there happens an action on one of our sockets
    Socket connectionSocket = welcomeSocket.accept();       //we make a new socket for each client connected to this server, so all connections go here.. In case user connects from browser or any other device then 'welcomeSocket' will accept it as well and get the information about who is trying connect etc., in such cases
    System.out.println("Just got connection with " +connectionSocket);  //This line just tells us which client has connected to this server, we can identify him now using his socket or IP.. Do not change any content inside brackets as these lines will remain the same even if our program is off until user changes something
    
    try {         /*try block with catch and finally blocks*/  //for dealing exceptions in your code. This deals exception, helps to clean up after yourself (if necessary) etc., you can use this for any kind of processing or data that needs done before socket operations get completed.. Use it if an error occurs during the execution
        InputStream input = connectionSocket.getInputStream();  //Create a 'input' object which reads from our connected client, we will read in here when they send us something and then do whatever is needed with them (such as storing or processing) via output stream to write back anything that needs done on the socket
        OutputStream out = connectionSocket.getOutputStream();  //Create a 'out' object which writes into our connected client, we will use this for communication when they send something and then do whatever is needed with it (such as storing or processing) via input stream to read from us.. Use these two objects inside try block only
        BufferedReader in = new BufferedReader(new InputStreamReader(input));  //A buffered reader will be used for reading data sent by our connected client, use this if you want your program able enough that it can handle textual streams (like HTTP/HTTPS requests).. Use these two objects inside try block only
        out.write("Hello Client".getBytes());   //Send back a simple message to the user once they've successfully logged in and been authenticated by server side, do not change this or use it when you want your program able enough that text can be readable as an HTTP/HTTPS request
        out.flush();  //This line is necessary for sure otherwise all data will remain buffered until manually flushed.. This forces the output buffer to write its contents into our connected client's socket, once they have received a response from us (after being authenticated by server) then you can send them some more text as normal
    } catch(Exception ex){   //All exceptions are caught and their details will be printed out in this block. This is to clean up any resources or make sure everything gets closed properly when an exception occurs..  You may need additional try blocks for each piece of code you have inside the 'try' if it involves multiple lines, separate them by commas etc., use these two objects and their nested exceptions within catch block only
        ex.printStackTrace();   //This will print out detailed information about what has happened when an exception occurs in your try-catch structure.. Use this to help you debug the error on server side or client end as well, once again with all details of whatever went wrong inside here…  This line is not removed and remains intact.
    } finally {   //This block will always be executed whether exceptions were caught (in case they occurred) nor did it run due to some unforeseen circumstances like out-of-memory error, etc., you can put your cleanup code inside this if needed..  It is useful for things that should happen when the try and catch parts of a block are done.
        connectionSocket.close();   //This will close our connected client's socket after we have finished with them (after they received data from us), no matter what happened in their previous sessions or not, so if you want your program able enough that it can handle textual streams/ HTTP requests..  Use this to help clean up when server side has processed a request and sent back the response
        welcomeSocket.close();   //This will close our listening socket (server) after we have finished with them (after they received any client), no matter what happened in their previous sessions or not, so if you want your program able enough that it can handle multiple clients.. Use this to help clean up when server side has processed all the requests and shut down properly
        System.out.println("Closing connections...");  //This line is just for informational purpose as we're closing everything now… Do not remove or modify content inside brackets, if these lines are removed then our program will fail once again when it hits this point of code which may occur due to out-of-memory error etc.
    }//end main method  //This line closes the class and makes sure that no one can reach here without seeing other contents in above methods after its declaration till now so ensure all content between brackets is necessary for your program.. Use these two lines inside a try block only to declare or end this part of code.
 }//end main method  //This line closes the class and makes sure that no one can reach here without seeing other contents in above methods after its declaration till now so ensure all content between brackets is necessary for your program.. Use these two lines inside a try block only to declare or end this part of code.
}//end main method  //This line closes the class and makes sure that no one can reach here without seeing other contents in above methods after its declaration till now so ensure all content between brackets is necessary for your program.. Use these two lines inside a try block only to declare or end this part of code.